final_template:
AWSTemplateFormatVersion: '2010-09-09'
Description: >
  CloudFormation Template that creates an Amazon Timestream Database and four Timestream Tables using a Lambda‐backed custom resource.
  This approach replaces the use of the deprecated AWS::Timestream::Database and AWS::Timestream::Table resource types.
  The custom resource invokes the Timestream CreateDatabase and CreateTable API operations.
  NOTE:
    • This template uses a temporary solution. A migration plan is documented in the Metadata section.
    • Future updates should replace the custom resource with supported CloudFormation resource types when available.
    • The Lambda function is not configured inside a VPC to ensure full outbound internet connectivity for reaching CloudFormation’s ResponseURL.

Metadata:
  MigrationPlan:
    Details: >
      This template currently leverages a Lambda‐backed custom resource to create a Timestream Database and Tables,
      as the native resource types (AWS::Timestream::Database and AWS::Timestream::Table) are in maintenance mode.
      Internal documentation and tech debt tracking note that a migration to supported resource types should be
      performed as soon as viable alternatives become available. Future maintainers are encouraged to monitor AWS service
      announcements and update this template accordingly.

Parameters:
  TimestreamDatabaseName:
    Type: String
    Default: timestream-db
    Description: The name of the Timestream Database.
  MemoryStoreRetentionPeriodInHours:
    Type: Number
    Default: 24
    Description: The retention period, in hours, for the MemoryStore.
  MagneticStoreRetentionPeriodInDays:
    Type: Number
    Default: 7
    Description: The retention period, in days, for the MagneticStore.

Resources:
  TimestreamLambdaExecutionRole:
    Type: AWS::IAM::Role
    Properties:
      AssumeRolePolicyDocument:
        Version: '2012-10-17'
        Statement:
          - Effect: Allow
            Principal:
              Service: lambda.amazonaws.com
            Action: sts:AssumeRole
      Path: /
      Policies:
        - PolicyName: TimestreamCustomResourcePolicy
          PolicyDocument:
            Version: '2012-10-17'
            Statement:
              - Effect: Allow
                Action:
                  - timestream:CreateDatabase
                  - timestream:DeleteDatabase
                  - timestream:CreateTable
                  - timestream:DeleteTable
                Resource: "*"
              - Effect: Allow
                Action:
                  - logs:CreateLogGroup
                  - logs:CreateLogStream
                  - logs:PutLogEvents
                Resource: arn:aws:logs:*:*:*
              - Effect: Allow
                Action:
                  - sns:Publish
                Resource: "*"

  TimestreamOperationsTopic:
    Type: AWS::SNS::Topic
    Properties:
      TopicName: timestream-operations-topic

  CustomTimestreamCreatorLambda:
    Type: AWS::Lambda::Function
    Properties:
      Handler: index.handler
      Runtime: nodejs24.x
      Role: !GetAtt TimestreamLambdaExecutionRole.Arn
      Timeout: 300
      Environment:
        Variables:
          TimestreamOperationsTopicArn: !Ref TimestreamOperationsTopic
      Code:
        ZipFile: |
          'use strict';
          const https = require("https");
          const url = require("url");
          const AWS = require("aws-sdk");
          const timestreamwrite = new AWS.TimestreamWrite();
          const sns = new AWS.SNS();

          // sendResponse sends a formatted JSON response to CloudFormation.
          function sendResponse(event, responseStatus, responseData, physicalResourceId) {
            return new Promise((resolve, reject) => {
              const responseBody = JSON.stringify({
                Status: responseStatus,
                Reason: responseStatus === "FAILED" ? responseData : "See the details in CloudWatch Log Stream",
                PhysicalResourceId: physicalResourceId || "NONE",
                StackId: event.StackId,
                RequestId: event.RequestId,
                LogicalResourceId: event.LogicalResourceId,
                Data: responseData
              });

              const parsedUrl = url.parse(event.ResponseURL);
              const options = {
                hostname: parsedUrl.hostname,
                port: 443,
                path: parsedUrl.path,
                method: "PUT",
                headers: {
                  "Content-Type": "application/json",
                  "Content-Length": Buffer.byteLength(responseBody)
                }
              };

              console.log("sendResponse: sending response to", event.ResponseURL);
              const request = https.request(options, (response) => {
                let responseString = "";
                response.on("data", (chunk) => responseString += chunk);
                response.on("end", () => {
                  console.log("sendResponse: CloudFormation responded with status:", response.statusCode, "body:", responseString);
                  resolve();
                });
              });

              request.on("error", (error) => {
                console.error("sendResponse: HTTP request error:", error);
                // Resolve immediately on error to avoid blocking.
                resolve();
              });

              request.write(responseBody);
              request.end();
            });
          }

          // Helper for adding timeout to promises.
          function withTimeout(promise, ms) {
            return new Promise((resolve, reject) => {
              const timeout = setTimeout(() => reject(new Error("Timeout after " + ms + " ms")), ms);
              promise.then((res) => {
                clearTimeout(timeout);
                resolve(res);
              }).catch((err) => {
                clearTimeout(timeout);
                reject(err);
              });
            });
          }

          exports.handler = async (event, context) => {
            context.callbackWaitsForEmptyEventLoop = false;
            console.log("REQUEST RECEIVED:", JSON.stringify(event));

            const props = event.ResourceProperties;
            const dbName = props.DatabaseName;
            const memRetention = parseInt(props.MemoryStoreRetentionPeriodInHours);
            const magRetention = parseInt(props.MagneticStoreRetentionPeriodInDays);
            let tables;
            try {
              tables = JSON.parse(props.Tables);
            } catch (err) {
              console.error("Error parsing Tables JSON:", err);
              return sendResponse(event, "FAILED", "Invalid Tables JSON: " + err, dbName);
            }

            if (event.RequestType === "Create" || event.RequestType === "Update") {
              const responseData = {
                DatabaseName: dbName,
                TableBatchWriteName: tables.TableBatchWrite.TableName,
                TableMemOnlyName: tables.TableMemOnly.TableName,
                TableMagneticOnlyName: tables.TableMagneticOnly.TableName,
                TableCommonAttributesName: tables.TableCommonAttributes.TableName,
                Note: "Timestream resource creation initiated asynchronously."
              };

              // Immediately send response to CloudFormation.
              const sendResPromise = sendResponse(event, "SUCCESS", responseData, dbName);

              // Offload asynchronous Timestream operations by publishing a message to SNS.
              const message = {
                operation: "create",
                DatabaseName: dbName,
                MemoryStoreRetentionPeriodInHours: memRetention,
                MagneticStoreRetentionPeriodInDays: magRetention,
                Tables: tables
              };
              sns.publish({
                TopicArn: process.env.TimestreamOperationsTopicArn,
                Message: JSON.stringify(message)
              }).promise().then(() => {
                console.log("SNS publish for create operation succeeded.");
              }).catch((err) => {
                console.error("SNS publish for create operation failed:", err);
              });

              // Return the sendResponse promise to signal completion to CloudFormation.
              return sendResPromise;
            } else if (event.RequestType === "Delete") {
              const sendResPromise = sendResponse(event, "SUCCESS", {}, dbName);

              const message = {
                operation: "delete",
                DatabaseName: dbName,
                Tables: tables
              };
              sns.publish({
                TopicArn: process.env.TimestreamOperationsTopicArn,
                Message: JSON.stringify(message)
              }).promise().then(() => {
                console.log("SNS publish for delete operation succeeded.");
              }).catch((err) => {
                console.error("SNS publish for delete operation failed:", err);
              });

              return sendResPromise;
            }
          };

  TimestreamResources:
    Type: Custom::TimestreamResources
    Properties:
      ServiceToken: !GetAtt CustomTimestreamCreatorLambda.Arn
      ServiceTimeout: 60
      DatabaseName: !Ref TimestreamDatabaseName
      MemoryStoreRetentionPeriodInHours: !Ref MemoryStoreRetentionPeriodInHours
      MagneticStoreRetentionPeriodInDays: !Ref MagneticStoreRetentionPeriodInDays
      Tables: >
        {
          "TableBatchWrite": {
            "TableName": "poc-table-01-batch-write",
            "Memory": true,
            "Magnetic": true
          },
          "TableMemOnly": {
            "TableName": "poc-table-02-older-records-memonly",
            "Memory": true,
            "Magnetic": false
          },
          "TableMagneticOnly": {
            "TableName": "poc-table-03-older-records-magnetic",
            "Memory": false,
            "Magnetic": true
          },
          "TableCommonAttributes": {
            "TableName": "poc-table-04-common-attributes",
            "Memory": true,
            "Magnetic": true
          }
        }

Outputs:
  DatabaseName:
    Description: The Timestream Database name created by the custom resource.
    Value: !GetAtt TimestreamResources.DatabaseName
  TableBatchWriteName:
    Description: The name of poc-table-01-batch-write configured with both Memory and Magnetic retention policies.
    Value: !GetAtt TimestreamResources.TableBatchWriteName
  TableMemOnlyName:
    Description: The name of poc-table-02-older-records-memonly configured with Memory retention policy only.
    Value: !GetAtt TimestreamResources.TableMemOnlyName
  TableMagneticOnlyName:
    Description: The name of poc-table-03-older-records-magnetic configured with Magnetic retention policy only.
    Value: !GetAtt TimestreamResources.TableMagneticOnlyName
  TableCommonAttributesName:
    Description: The name of poc-table-04-common-attributes configured with both retention policies.
    Value: !GetAtt TimestreamResources.TableCommonAttributesName

